// src/domain/theme/styles/modules/variables.ts
var CSS_VARIABLES = `/* Obsidian Garden */
:root {
  --bg: #faf9f6;
  --bg-elevated: #ffffff;
  --bg-subtle: #f2f0eb;
  --text: #1c1917;
  --text-secondary: #78716c;
  --text-tertiary: #a8a29e;
  --accent: #4f46e5;
  --accent-hover: #4338ca;
  --accent-subtle: rgba(79, 70, 229, 0.08);
  --accent-ring: rgba(79, 70, 229, 0.2);
  --warm: #d97706;
  --warm-subtle: rgba(217, 119, 6, 0.1);
  --border: #e7e5e4;
  --border-strong: #d6d3d1;
  --code-bg: #f5f5f4;
  --shadow-1: 0 1px 2px 0 rgba(0,0,0,0.04);
  --shadow-2: 0 1px 3px 0 rgba(0,0,0,0.07), 0 1px 2px -1px rgba(0,0,0,0.04);
  --shadow-3: 0 4px 6px -1px rgba(0,0,0,0.07), 0 2px 4px -2px rgba(0,0,0,0.04);
  --shadow-4: 0 10px 15px -3px rgba(0,0,0,0.08), 0 4px 6px -4px rgba(0,0,0,0.03);
  --font-serif: "Source Serif 4", Georgia, "Times New Roman", serif;
  --font-sans: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  --font-mono: "SF Mono", "Fira Code", "JetBrains Mono", Consolas, monospace;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; -webkit-text-size-adjust: 100%; }

body {
  font-family: var(--font-sans);
  line-height: 1.75;
  color: var(--text);
  background: var(--bg);
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}`;

// src/domain/theme/styles/modules/navigation.ts
var CSS_NAVIGATION = `/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550
   Navigation
   \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */
.garden-nav {
  position: sticky;
  top: 0;
  z-index: 50;
  background: rgba(250, 249, 246, 0.82);
  backdrop-filter: blur(16px) saturate(1.8);
  -webkit-backdrop-filter: blur(16px) saturate(1.8);
  border-bottom: 1px solid var(--border);
}

.garden-nav-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 60px;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
}

.garden-brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.garden-logo {
  width: 28px;
  height: 28px;
  background: linear-gradient(135deg, #059669 0%, #10b981 100%);
  border-radius: 7px;
  display: grid;
  place-items: center;
  box-shadow: 0 1px 3px rgba(5, 150, 105, 0.3);
}

.garden-logo::after {
  content: "";
  width: 10px;
  height: 10px;
  border: 2px solid rgba(255,255,255,0.9);
  border-radius: 50% 50% 50% 0;
  transform: rotate(-45deg);
}

.garden-site-title {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  font-weight: 600;
  color: var(--text);
  text-decoration: none;
  letter-spacing: -0.02em;
}

.garden-site-title:hover { color: var(--accent); }

.garden-menu-toggle {
  display: none;
  background: none;
  border: none;
  padding: 8px;
  cursor: pointer;
  border-radius: 6px;
}

.garden-menu-toggle:hover { background: var(--bg-subtle); }

.garden-menu-icon {
  display: block;
  width: 20px;
  height: 2px;
  background: var(--text);
  border-radius: 2px;
  position: relative;
}

.garden-menu-icon::before,
.garden-menu-icon::after {
  content: "";
  position: absolute;
  width: 20px;
  height: 2px;
  background: var(--text);
  border-radius: 2px;
  left: 0;
  transition: 0.2s ease;
}

.garden-menu-icon::before { top: -6px; }
.garden-menu-icon::after { top: 6px; }

.garden-menu-active .garden-menu-icon { background: transparent; }
.garden-menu-active .garden-menu-icon::before { top: 0; transform: rotate(45deg); }
.garden-menu-active .garden-menu-icon::after { top: 0; transform: rotate(-45deg); }

.garden-nav-links { display: flex; gap: 4px; }

.garden-nav-link {
  padding: 6px 14px;
  color: var(--text-secondary);
  text-decoration: none;
  font-size: 0.88rem;
  font-weight: 500;
  border-radius: 6px;
  transition: all 0.15s ease;
}

.garden-nav-link:hover {
  color: var(--accent);
  background: var(--accent-subtle);
}`;

